mapper.select:
SELECT U.ID, U.PLANT, U.GUBUN, U.EMPID, U.NAME, U.EMAIL, U.DEPTCD, D.DEPTNM AS DEPT_NAME, U.JIKGUB, U.PASS, U.TEL, U.MOBILE, U.USEAREA, U.SHOWYN FROM TBL_COM_MEMBERS U LEFT JOIN TBL_COM_DEPT D ON U.DEPTCD = D.DEPTCD WHERE 1=1
AND U.PLANT = #{PLANT}
AND U.NAME LIKE '%' + #{NAME} + '%'
AND U.DEPTCD = #{DEPTCD}
AND U.SHOWYN = #{SHOWYN}
ORDER BY U.EMPID ASC
